import math

def h(x):
    return math.sin(x ** 2)

def h_prime(x):
    u = x ** 2
    return math.cos(u) * (2 * x)  # f'(g(x)) * g'(x)

x = 1.5
print("h'(x):", h_prime(x))

import torch

def f(g_x):
    return torch.sin(g_x)

def g(x):
    return x ** 2

x = torch.tensor(1.5, requires_grad=True)
y = f(g(x))
y.backward()
print("autograd:", x.grad.item())
print("manual:", torch.cos(x.detach() ** 2) * (2 * x.detach())).item())
